    for (const [u, v, w] of edges) {
        graph[u].push({ to: v, weight: w });
    }

    const dist = new Array(n).fill(0).map(() => new Array(2).fill(1e18));
    dist[0][0] = 0; // 0: not used switch, 1: used switch

    const pq = new PriorityQueue((a, b) => a[0] - b[0]);
    pq.enqueue([0, 0, 0]); // [distance, node, switchUsed]

    while (!pq.isEmpty()) {
        const [d, u, sw] = pq.dequeue();

        if (u === n - 1) return d;

        if (d > dist[u][sw]) continue;

        for (const { to, weight } of graph[u]) {
            if (sw === 0) {
                // No switch used, can choose to use it or not
                // Option 1: don't use the switch, go normally
                if (dist[u][0] + weight < dist[to][0]) {
                    dist[to][0] = dist[u][0] + weight;
                    pq.enqueue([dist[to][0], to, 0]);
                }
                // Option 2: use the switch, reverse the edge
                if (dist[u][1] + 2 * weight < dist[to][1]) {
                    dist[to][1] = dist[u][1] + 2 * weight;
                    pq.enqueue([dist[to][1], to, 1]);
                }
            } else {
                // Switch already used, can't use it again
                if (dist[u][1] + weight < dist[to][1]) {
                    dist[to][1] = dist[u][1] + weight;
                    pq.enqueue([dist[to][1], to, 1]);
                }
            }
        }
    }

    return -1;
}

